import bisect

class Solution:
    def minimalKSum(self, nums, k):
        uniq = sorted(set(nums))

        def free_count(u):
            idx = bisect.bisect_right(uniq, u)
            return u - idx

        lo, hi = 1, 2 * 10 ** 9
        while lo < hi:
            mid = (lo + hi) // 2
            if free_count(mid) >= k:
                hi = mid
            else:
                lo = mid + 1
        u = lo
        idx = bisect.bisect_right(uniq, u)
        return u * (u + 1) // 2 - sum(uniq[:idx])

