class Solution:
    def minimalKSum(self, nums, k):
        uniq = sorted(set(nums))
        total = 0
        prev = 0
        remaining = k
        for v in uniq:
            if remaining <= 0:
                break
            gap = v - prev - 1
            if gap > 0:
                take = min(gap, remaining)
                total += (prev + 1 + prev + take) * take // 2
                remaining -= take
            prev = v
        if remaining > 0:
            total += (prev + 1 + prev + remaining) * remaining // 2
        return total

