var minimalKSum = function(nums, k) {
    const uniq = Array.from(new Set(nums)).sort((a, b) => a - b);
    let total = 0;
    let prev = 0;
    let remaining = k;
    for (const v of uniq) {
        if (remaining <= 0) break;
        const gap = v - prev - 1;
        if (gap > 0) {
            const take = Math.min(gap, remaining);
            total += (prev + 1 + prev + take) * take / 2;
            remaining -= take;
        }
        prev = v;
    }
    if (remaining > 0) {
        total += (prev + 1 + prev + remaining) * remaining / 2;
    }
    return total;
};
